@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasksForStatus(\"To Do\")"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="task => MoveTask(task, \"In Progress\")"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasksForStatus(\"In Progress\")"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, \"To Do\")"
                     OnMoveRight="task => MoveTask(task, \"Done\")"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasksForStatus(\"Done\")"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private IReadOnlyList<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

